#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 main = texture( sampler_main, vUv ).xyz;
    vec3 mblur = GetBlur1( vUv );
    main = ( (main-mblur*.5)*3 );
    float zoom = 1+.5*( (q9*vUvOriginal.y-q8*vUvOriginal.x)*6+vRadius*sin(vAngle+2-q3-q4)*mblur.z*3)*(.01+(q1-q2)*.01);
    float rot = (mblur.y-mblur.x)*(q7-q8)*.5;
    vec2 zcr = vec2(.5,.5);
    vec2 cr = vec2(.5,.5);
    vec2 newuv = vUv;

    ///////////////////rotation////////////////
    newuv = vUv - cr;
    float s = sin(rot);
    float c = cos(rot);
    newuv = vec2( (vUv.x-cr.x)*c-(vUv.y-cr.y)*s , (vUv.x-cr.x)*s+(vUv.y-cr.y)*c  );
    newuv = newuv + cr;
    ///////////////////rotation////////////////

    ///////////////////zoom////////////////
    newuv = newuv-zcr;
    newuv = newuv * zoom;
    newuv= newuv+zcr;
    ///////////////////zoom////////////////


    vec3 colorwarp = texture( sampler_main, newuv );

    vec3 color = texture(sampler_rand02, newuv ).xyz;
//    ret = ( (  (colorwarp*main*3-normalize(color)) ) );
    ret= mix(colorwarp,main*color,1-sin((color-colorwarp)*6));
vec3 ret7=ret;
if(uFrame%3==0)ret.z=.71-ret7.x;

    // darken (decay) over uTime
    ret *= 0.96; //or try: ret -= 0.004;


ret.xyz = texture(sampler_main, vUvOriginal).xyz*vec3(.97,1,.97) - vec3(.03,0,.03);

if(uFrame%5==0)ret.x=.71-ret7.y;


ret.z += GetBlur1(vUvOriginal).z*.45;
ret.x += GetBlur1(vUvOriginal).z*.05 + GetBlur3(vUvOriginal).z*.05;
ret.z -= ret.x;

vec2 pixelsize = uTexSize.zw;
ret.y = clamp01(texture( sampler_pw_main,vUvOriginal).y);

float1 conway = texture( sampler_pw_main, vUvOriginal + vec2(-1,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(0,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,-1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(-1,0)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,0)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(-1,1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(0,1)*pixelsize).y;
       conway += texture( sampler_pw_main, vUvOriginal + vec2(1,1)*pixelsize).y;

float1 test = q5*(1-GetBlur1(vUvOriginal).y)*(1-GetBlur2(vUvOriginal).y)*(1-GetBlur3(vUvOriginal).y);

conway -= texture( sampler_pw_main, vUvOriginal).x;


if (conway > 1) {
if (clamp01(ret.y) == 0) {
ret.y = floor(test*99)*1;
}
}

ret.y -= ret.x;

ret.xyz -= audioLow/7-audioMid/11.2 ;

if(uFrame%7==0)ret.y=.71-ret7.z;


  fragColor = ret;
}

